// ─── 因果境界 ───
function getKarmaTier(k){
  if(k>=500)return {t:'圆环之理',e:'🌌',l:6,clr:'#e040fb',d:'因果缠绕成环。好感度极易提升——但精神负担也达到极限。'};
  if(k>=350)return {t:'编织者',e:'🕸️',l:5,clr:'#bc8cff',d:'你开始理解命运的丝线。羁绊加深更快——但灵魂的裂痕也在扩大。'};
  if(k>=200)return {t:'干涉者',e:'⚡',l:4,clr:'#58a6ff',d:'你的存在开始扭曲既定的轨迹。好感+3，精神消耗+1。'};
  if(k>=100)return {t:'观测者',e:'👁️',l:3,clr:'#3fb950',d:'你能看到命运的分支。天赋3选1，好感+2，精神消耗+0.5。'};
  if(k>=50) return {t:'觉醒者',e:'✨',l:2,clr:'#f0c040',d:'你隐约感到——这不是第一次了。全属性+1，初始好感+2。'};
  return       {t:'凡人',e:'😶',l:1,clr:'#8b949e',d:'第一次踏入这个百日。一切才刚刚开始。'};
}

// ─── 因果被动加成（在initG中调用，不消耗因果值）───
function applyKarmaPassive(){
  const karma=G.karma||0;
  const tier=getKarmaTier(karma);
  G._karmaTier=tier;

  // 觉醒者 (≥50): 全属性+1，初始好感+3
  if(karma>=50){
    Object.keys(G.attr).forEach(k=>G.attr[k]=clamp(G.attr[k]+1,1,10));
    const affBonus=karma>=500?8:karma>=350?6:karma>=200?5:karma>=100?4:3;
    Object.keys(CH).forEach(k=>G.aff[k]=(G.aff[k]||0)+affBonus);
  }
  // 观测者 (≥100): 天赋多抽1个（在rCreate中处理）
  // 干涉者 (≥200): 好感加成+2（在execChoice中处理）
  // 编织者 (≥350): 支线触发率翻倍（在rPlay中处理）
  // 圆环之理 (≥500): 隐藏结局可触发（在rEnd中处理）

  return tier;
}

// ─── 因果值对好感度加成的被动影响（在execChoice中调用）───
function getKarmaAffBonus(){
  const k=G.karma||0;
  if(k>=500)return 5;  // 圆环之理：因果缠绕，羁绊极速
  if(k>=350)return 4;  // 编织者
  if(k>=200)return 3;  // 干涉者
  if(k>=100)return 2;  // 观测者
  if(k>=50)return 1;   // 觉醒者
  return 0;
}

// ─── 因果值对事件触发概率的影响 ───

// ─── 因果值越高→精神消耗越大（Madoka Portable核心机制：因果=祝福+诅咒）───
function getKarmaSprPenalty(){
  const k=G.karma||0;
  if(k>=500)return 3;    // 圆环之理：命运重压——承载无数轮回的记忆
  if(k>=350)return 2;    // 编织者
  if(k>=200)return 1;    // 干涉者
  if(k>=100)return 0.5;  // 观测者：轻微负担
  return 0;              // 凡人/觉醒者：无忧无虑
}

function getKarmaEventBonus(){
  const k=G.karma||0;
  if(k>=500)return 0.25; // 圆环之理：隐藏事件频发
  if(k>=350)return 0.20; // 编织者
  if(k>=200)return 0.15; // 干涉者
  if(k>=100)return 0.10; // 观测者
  if(k>=50)return 0.05;  // 觉醒者
  return 0;
}
