// ─── 家庭共享住宅（兄弟/双胞胎同居）───
const FAMILY_HOMES={
  leishi:{name:'雷家',members:['leishi','kamier','leizhi']},
  kamier:{name:'雷家',members:['leishi','kamier','leizhi']},
  leizhi:{name:'雷家',members:['leishi','kamier','leizhi']},
  aibi:{name:'艾比家',members:['aibi','aimi']},
  aimi:{name:'艾比家',members:['aibi','aimi']},
};
function getHomeInfo(charId){
  const host=CH[charId];if(!host)return null;
  const fam=FAMILY_HOMES[charId];
  if(fam){
    const members=fam.members.map(id=>CH[id]).filter(Boolean);
    const otherMembers=members.filter(m=>m.id!==charId);
    return{host,members,otherMembers,isFamily:true,displayName:fam.name,homeLabel:fam.name,allEmoji:members.map(m=>m.e).join(''),allNames:members.map(m=>m.e+' '+m.n).join('、')};
  }
  return{host,members:[host],otherMembers:[],isFamily:false,displayName:host.n+'家',homeLabel:host.n+'家',allEmoji:host.e,allNames:host.e+' '+host.n};
}
function pickHomestay(talentIds){
  // 30%概率从天赋关联角色中选，70%纯随机
  if(talentIds&&talentIds.length>0&&Math.random()<0.3){
    const rel=[];talentIds.forEach(t=>{if(TALENT_HOME_LINK[t])rel.push(...TALENT_HOME_LINK[t]);});
    if(rel.length>0)return pk([...new Set(rel)]);
  }
  return pk(HOMESTAY_POOL);
}

