// ─── 课堂事件模板（用 {{}} 作为占位符，运行时替换）───
const CLASS_EVENTS=[
  {t:'数学课·提问',x:'数学老师在黑板上写了一题。\n\n粉笔落下。\n\n「这道题——请一位同学上来做。」\n\n你感觉到周围同学的目光在四处躲闪。而{{mc.e}} {{mc.n}}{{pk:正在认真演算|低头翻书|已经写完了在转笔|悄悄推了你一下}}。',
    c:[{t:'主动举手上去做',a:[{id:'mc',v:dv(6)}],f:'你做对了。老师点了点头。{{mc.n}}在你下来时对你笑了一下。'},
       {t:'小声和{{mc.n}}讨论答案',a:[{id:'mc',v:dv(5)}],f:'你们在下面嘀咕了几句。答案是对的——而且这样讨论比一个人做更有趣。'},
       {t:'低头祈祷不要被点到',a:[],f:'老师叫了另一个人。你松了口气——但{{mc.n}}似乎注意到了你的反应。'}]},
  {t:'语文课·小组讨论',x:'语文课。\n\n「四人一组——讨论这篇文章的主题。」\n\n{{mc.e}} {{mc.n}}{{pk:抱着书挪了过来|刚好被分到你这组|在找组员}}。{{sc?sc.e+ sc.n+也凑了过来。:}}',
    c:[{t:'认真发表自己的看法',a:[{id:'mc',v:dv(5)},{id:'sc',v:dv(3)}],f:'{{mc.n}}听得很仔细{{sc?——{{sc.n}}也在旁边点头。:。}}讨论结束时——{{mc.n}}说「你刚才那个观点很有意思」{{sc?——{{sc.n}}补了一句「我同意」。:。}}'},
       {t:'让{{mc.n}}先说，自己补充',a:[{id:'mc',v:dv(4)},{id:'sc',v:dv(3)}],f:'你安静地听着。在{{mc.n}}说完后补了一句{{sc?——{{sc.n}}看了你一眼——「配合得不错。」:——Ta看了你一眼，像是在说「默契」。}}'}]},
  {t:'英语课·传纸条',x:'英语课。\n\n老师在讲语法——但教室里偶尔有纸条在飞。\n\n你桌上突然多了一张折好的纸条。{{mc.e}} {{mc.n}}{{pk:在你斜后方偷偷挥手|装作若无其事|用笔戳了戳你后背}}。',
    c:[{t:'打开纸条看——然后回复',a:[{id:'mc',v:dv(7)}],f:'纸条上写的是「下课后要不要一起去买饮料？」你写了「好」。折回去的时候——老师差点发现。'},
       {t:'把纸条收起来，下课再看',a:[{id:'mc',v:dv(3)}],f:'你忍了一节课没看。下课打开——是Ta画的一只猫。很丑。但你笑了。'}]},
  {t:'实验课·意外',x:'化学实验室。\n\n{{mc.e}} {{mc.n}}负责的实验——\n\n{{pk:液体变成了奇怪的颜色|烧杯冒出了烟|量筒摔了|忘了加催化剂导致什么都没发生}}。',
    c:[{t:'赶紧帮忙收拾/调整',a:[{id:'mc',v:dv(8)}],f:'你反应很快。两个人手忙脚乱地抢救实验——最后居然成功了。老师都没发现。'},
       {t:'在旁边帮忙记录数据',a:[{id:'mc',v:dv(4)}],f:'虽然实验出了意外——但你记录的数据帮上了忙。{{mc.n}}松了一口气。'}]},
  {t:'自习课·偷懒',x:'自习课。\n\n教室里安静得只剩翻书声。\n\n{{mc.e}} {{mc.n}}{{pk:趴在桌上|在课本下面藏了一本漫画|悄悄在画画|用笔在桌上刻字|望着窗外发呆}}。',
    c:[{t:'假装没看见——但帮忙望风',a:[{id:'mc',v:dv(6)}],f:'老师经过的时候你咳嗽了一声。Ta秒速坐直。老师走后——对你比了个大拇指。'},
       {t:'小声提醒「老师在看你」',a:[{id:'mc',v:dv(3)}],f:'Ta赶紧端正了坐姿。虽然被提醒有点尴尬——但Ta知道你是好意。'}]},
  {t:'课间·分享',x:'课间5分钟。\n\n{{mc.e}} {{mc.n}}{{pk:拿出一包零食|分享了一首新歌|掏出一个奇怪的挂件|在手机上刷到了好笑的视频}}。',
    c:[{t:'自然地凑过去',a:[{id:'mc',v:dv(6)}],f:'Ta分给了你一半。上课铃响了——两个人手忙脚乱地把东西藏起来。'},
       {t:'在旁边微笑看着',a:[{id:'mc',v:dv(3)}],f:'Ta注意到了你的目光——回头对你笑了一下。课间短暂——但很暖。'}]},
  {t:'美术课·被画',x:'美术课。主题是「画你身边的人」。\n\n{{mc.e}} {{mc.n}}{{pk:偷偷在看你|画得特别认真|把画藏了起来不让人看|画纸上——好像是你的侧脸}}。',
    c:[{t:'假装没发现——但配合地保持姿势',a:[{id:'mc',v:dv(8)}],f:'下课后Ta把画塞进了书包。但你瞥到了一眼——画得真的很好。'},
       {t:'直接问「你在画我吗？」',a:[{id:'mc',v:dv(5)}],f:'Ta脸红了——把画纸翻了过去。「没——没有。」但你看到了。画的是你。'}]},
  {t:'体育课·组队',x:'体育课。\n\n「两人一组——」\n\n{{mc.e}} {{mc.n}}{{pk:目光扫了一圈——看向了你|站在原地等着被选|径直朝你走过来}}。',
    c:[{t:'主动向Ta走去',a:[{id:'mc',v:dv(7)}],f:'你们成了一组。练习的时候Ta意外地认真——但失误了会笑得很开。'},
       {t:'站在原地——等Ta来找你',a:[{id:'mc',v:dv(5)}],f:'果然——Ta过来了。「一起？」你说好。阳光下——汗水在发光。'}]},
  {t:'音乐课·合唱',x:'音乐课。大合唱。\n\n{{mc.e}} {{mc.n}}站在你旁边。\n\n歌曲是{{pk:一首老歌|最近很火的流行曲|一首奇怪的童谣}}。\n\n你们的声音混在一起的时候——',
    c:[{t:'认真跟着唱',a:[{id:'mc',v:dv(5)}],f:'你们的声线意外地和。唱到高音的时候Ta破了音——两个人都笑了。'},
       {t:'小声和Ta吐槽这首歌',a:[{id:'mc',v:dv(4)}],f:'你们在下面偷偷聊天。被老师瞪了一眼——但Ta没忍住又笑了。'}]},
  {t:'考试·紧张',x:'小测验。\n\n教室安静。只有笔在纸上的沙沙声。\n\n{{mc.e}} {{mc.n}}{{pk:疯狂翻卷子|在咬笔帽|额头冒汗|看起来胸有成竹}}。',
    c:[{t:'专注做自己的——考完后交换对答案',a:[{id:'mc',v:dv(5)}],f:'考完后你们对了答案。Ta错了一题——但你安慰说「那道题确实很坑」。'},
       {t:'趁老师不注意，给Ta指了一下',a:[{id:'mc',v:dv(8)}],f:'你冒了风险。Ta看到了——赶紧改了。考完后Ta小声说了谢谢。'}]},
  {t:'发成绩·安慰',x:'成绩公布了。\n\n{{mc.e}} {{mc.n}}{{pk:考得不太理想——趴在桌上|比上次进步了一点——在偷偷握拳|考砸了——把卷子塞进了书包最深处}}。',
    c:[{t:'走过去说「下次一起复习吧」',a:[{id:'mc',v:dv(9)}],f:'Ta抬起头。眼睛有点红——但笑了。\n「……说好了。」'},
       {t:'悄悄在Ta桌上放了一颗糖',a:[{id:'mc',v:dv(5)}],f:'Ta发现糖的时候愣了一秒。然后剥开糖纸吃了——好像心情好了一点点。'}]},
  {t:'换座位·邻桌',x:'今天换座位。\n\n{{mc.e}} {{mc.n}}{{pk:坐到了你旁边|被调到了你前面|换到了你斜对角}}。\n\n「请多关照。」',
    c:[{t:'开心地打招呼',a:[{id:'mc',v:dv(6)}],f:'Ta也笑了。新座位——意味着更多的交集。更多借橡皮、传纸条、课间闲聊的机会。'},
       {t:'帮Ta搬桌子/放书',a:[{id:'mc',v:dv(4)}],f:'你顺手帮了忙。Ta说了谢谢——然后发现你们的铅笔盒是同款。'}]},
  {t:'值日·一起',x:'今天轮到你值日。\n\n{{mc.e}} {{mc.n}}{{pk:也轮到了值日|主动留下来帮忙|被老师罚了值日——满脸不服}}。\n\n教室空了——只剩你们。',
    c:[{t:'分工合作——擦黑板/扫地',a:[{id:'mc',v:dv(7)}],f:'值日很快做完了。夕阳从窗户照进来——教室里安静而温暖。你们多待了一会儿。'},
       {t:'边做值日边聊天',a:[{id:'mc',v:dv(5)}],f:'聊着聊着——值日就做完了。你知道了Ta喜欢什么、讨厌什么。这些小事——很重要。'}]},
  {t:'生病·课堂',x:'上课时。\n\n{{mc.e}} {{mc.n}}{{pk:脸色很差|一直在吸鼻子|趴在桌上不起来|嘴唇发白}}。\n\n老师还没注意到。',
    c:[{t:'下课陪Ta去保健室',a:[{id:'mc',v:dv(10)}],f:'校医说是低血糖。你帮Ta倒了热水。Ta握着杯子——「你真好。」声音很轻。'},
       {t:'帮Ta抄了今天的笔记',a:[{id:'mc',v:dv(6)}],f:'第二天你把工整的笔记本放在Ta桌上。Ta翻开的时候——沉默了很久。'}]},
  {t:'班会·活动策划',x:'班会。\n\n班主任说下个月有班级展示。\n\n「谁来负责策划？」\n\n{{mc.e}} {{mc.n}}{{pk:举了手|被大家推举出来|偷偷看你——好像在邀请你一起}}。',
    c:[{t:'举手：「我和Ta一起来」',a:[{id:'mc',v:dv(8)}],f:'你们一起负责了这次策划。放学后讨论了很久——虽然累但很充实。'},
       {t:'在下面小声说「需要帮忙的话叫我」',a:[{id:'mc',v:dv(4)}],f:'Ta点了点头。后来真的来找你帮忙了——你当然没有拒绝。'}]},
  {t:'走神·被点名',x:'课上。\n\n{{mc.e}} {{mc.n}}显然在走神——\n\n{{pk:盯着窗外|在纸上画小涂鸦|眼神放空|在偷偷看手机}}。\n\n老师突然喊了Ta的名字。',
    c:[{t:'小声告诉Ta答案/页码',a:[{id:'mc',v:dv(8)}],f:'你飞快地指了一下课本。Ta反应过来——勉强答上了。坐下后对你感激地看了一眼。'},
       {t:'假装掉笔——吸引老师注意力',a:[{id:'mc',v:dv(5)}],f:'你蹲下去捡笔。老师瞪了你一眼但节奏被打断了。{{mc.n}}趁机回了神。'}]},
];

// ─── 借宿事件模板（用 {{}} 作为占位符，运行时替换）───
const HOME_EVENTS={
  morning:[
    {t:'起床',x:'闹钟响了。\n\n你从被窝里挣扎出来。\n\n厨房传来动静——{{hs.e}} {{hs.n}}{{pk:已经在做早餐了|正在刷牙|在沙发上睡着——还没醒|对着镜子整理头发|在看早间新闻}}。',
      c:[{t:'去帮忙做早餐',a:[{id:'hs',v:dv(6)}],f:'你们一起做了早餐。虽然只是简单的吐司和牛奶——但两个人一起吃的味道总是不一样。'},
         {t:'说「早上好——」然后去洗漱',a:[{id:'hs',v:dv(3)}],f:'Ta回了你一句随意的早安。日常的——但温暖的。'}]},
    {t:'早餐',x:'餐桌上。\n\n{{hs.e}} {{hs.n}}把早餐摆好。\n\n{{pk:「昨晚睡得好吗？」|「今天有测验吧——复习了吗？」|「你头发翘起来了。」|「尝尝这个——我新学的。」}}',
      c:[{t:'边吃边聊——聊今天的计划',a:[{id:'hs',v:dv(5)}],f:'你们聊着天。早餐时间很短——但足以让人对新的一天充满期待。'},
         {t:'帮Ta收拾餐具',a:[{id:'hs',v:dv(3)}],f:'吃完后你主动洗碗。Ta在旁边擦桌子——这样的分工已经很自然了。'}]},
    {t:'出门',x:'快迟到了。\n\n{{hs.e}} {{hs.n}}穿上鞋——\n\n{{pk:「你书包拉链没拉。」|「便当带了吗？」|在门口等你|已经推开门——阳光涌进来}}。',
      c:[{t:'加快脚步跟上',a:[{id:'hs',v:dv(5)}],f:'你们几乎是小跑着出门的。路上——Ta说了句「今天的天气——适合迟到。」你笑了。'},
         {t:'帮Ta拿了忘带的东西',a:[{id:'hs',v:dv(4)}],f:'你瞥见桌上Ta的钥匙——顺手拿了。Ta在门口摸口袋时——你递了过去。「……谢谢。」'}]},
  ],
  evening:[
    // ─── 低好感(0-30)：礼貌距离，日常观察 ───
    {t:'回家',minAff:0,x:'天已经暗下来了。\n\n你用钥匙开门——屋里亮着灯。\n\n{{hs.e}} {{hs.n}}{{pk:在客厅等你|从房间探出头「回来啦？」|在厨房——香味飘了出来|已经躺在沙发上睡着了}}。',
      c:[{t:'「我回来了——」自然地换鞋进屋',a:[{id:'hs',v:dv(5)}],f:'Ta应了一声。房间里很温暖——这是你在这里的第{{G.day}}天。已经开始习惯了。'},
         {t:'轻手轻脚——怕吵醒Ta',a:[{id:'hs',v:dv(4)}],f:'你轻轻地关上门。但Ta还是醒了——看到你之后笑了笑。「回来了啊。」'}]},
    {t:'晚饭',minAff:0,x:'晚饭时间。\n\n{{hs.e}} {{hs.n}}做了{{pk:咖喱饭|拉面|炒饭|火锅——只有两个人的|外卖——披萨}}。\n\n两个人坐在桌边。',
      c:[{t:'「好吃——」真心地夸',a:[{id:'hs',v:dv(7)}],f:'Ta愣了一下——然后笑了。\n「那就多吃点。」Ta往你碗里又夹了一筷子菜。'},
         {t:'聊今天发生的事',a:[{id:'hs',v:dv(5)}],f:'你把学校里的事讲给Ta听。Ta有时笑有时吐槽——不知不觉吃完了。'}]},
    {t:'写作业',minAff:0,x:'晚上。\n\n你和{{hs.e}} {{hs.n}}在同一张桌上写作业。\n\n{{pk:「这道题你帮我看看——」|答案对不上——你算一遍？|两人的笔尖沙沙响|中场休息——Ta去拿了零食}}。',
      c:[{t:'耐心地讲解',a:[{id:'hs',v:dv(6)}],f:'你讲得很清楚。Ta恍然大悟的表情——让你莫名有成就感。'},
         {t:'分工——你写数学Ta写英语',a:[{id:'hs',v:dv(4)}],f:'虽然这种"分工"不太对——但效率确实高。做完后相视一笑。'}]},
    {t:'各自忙',minAff:0,x:'客厅里。\n\n你坐在沙发这头。{{hs.e}} {{hs.n}}坐在那头。\n\n电视开着——但没人在看。\n\n{{pk:Ta在看手机——偶尔抬头看你一眼|你在翻书——Ta刷着题|窗外有车经过——灯扫过天花板|钟在走——很慢}}。',
      c:[{t:'安静地待着——不用说话',a:[{id:'hs',v:dv(3)}],f:'沉默。但不算尴尬。\n\nTa翻了一页书。你换了条腿翘着。\n\n这种安静——像冬天的暖气。不需要理由。'},
         {t:'打破沉默——「你在看什么？」',a:[{id:'hs',v:dv(5)}],f:'Ta把手机屏幕偏过来——一个搞笑视频。\n你们一起笑了。然后不知不觉聊了半小时。'}]},
    {t:'雨天夜晚',minAff:0,x:'窗外在下雨。\n\n{{hs.e}} {{hs.n}}{{pk:站在窗前——看雨|给窗台的植物挪了个位置——「淋太多不好」|在关窗——「今晚有点凉」|说「下雨的晚上——最适合什么都不做」}}。\n\n雨声。屋里很暖。',
      c:[{t:'走到窗边——一起看雨',a:[{id:'hs',v:dv(6)}],f:'玻璃上——雨水在往下滑。\n\n你和Ta的影子映在窗上。\n谁都没说话。但你觉得——这种时刻比很多对话都近。'},
         {t:'「明天会停吗」',a:[{id:'hs',v:dv(4)}],f:'Ta看了看窗外。\n「不知道。但雨天的晚上——也挺好的。」\n然后Ta去泡了杯热茶。\n顺手也给你泡了一杯。'}]},
    // ─── 中好感(30-60)：轻松的日常，彼此熟悉 ───
    {t:'客厅·闲谈',minAff:30,x:'作业做完了。\n\n你和{{hs.e}} {{hs.n}}在客厅。电视开着——但没人认真看。\n\n{{pk:「你有喜欢的人吗——」|「100天后——你会去哪里？」|「如果时间能停在这里就好了。」|「明天要不要去哪里逛逛？」}}',
      c:[{t:'认真地回答',a:[{id:'hs',v:dv(8)}],f:'你回答了。Ta沉默了一会儿——然后在沙发上换了个姿势。\n「这样啊。」但Ta的声音变轻了。'},
         {t:'反问「那你呢？」',a:[{id:'hs',v:dv(6)}],f:'Ta没有回答。但Ta的沉默——好像说了很多。'}]},
    {t:'一起看电影',minAff:30,x:'{{hs.e}} {{hs.n}}翻出{{pk:一张老DVD|一部很烂的恐怖片——「因为够烂才好看」|一部文艺片——Ta说是以前最喜欢的|一部喜剧——「这个我看过三遍了」}}。\n\n「看吗？」\n\n电视的光在客厅里一闪一闪。',
      c:[{t:'「当然看——」坐到沙发中间',a:[{id:'hs',v:dv(7)}],f:'电影放到一半——你们都忘了进度条。\n\nTa笑的时候你正好也在笑。\nTa紧张的时候——你发现自己也屏住了呼吸。'},
         {t:'去拿毯子和零食——「看电影要有仪式感」',a:[{id:'hs',v:dv(5)}],f:'你抱来毯子和薯片。Ta眼睛亮了。\n两人裹在同一条毯子里——虽然隔了半个沙发。\n但毯子够大。'}]},
    {t:'深夜泡面',minAff:30,x:'快十一点了。\n\n你饿了——准备去厨房偷吃点什么。\n\n然后发现{{hs.e}} {{hs.n}}也在。\n\n{{pk:「你也饿了？」|「嘘——我找到一个好东西——」|两人对视——然后都笑了|Ta手里——两碗方便面}}。',
      c:[{t:'一起泡面——坐在厨房地板上吃',a:[{id:'hs',v:dv(8)}],f:'深夜的泡面——比任何大餐都好吃。\n\n你们坐在地板上。厨房的灯没开——只有走廊的光。\nTa说了句「以后——会记得这个味道吧。」\n你没有回答。但你知道——会的。'},
         {t:'「我帮你加个蛋——」',a:[{id:'hs',v:dv(6)}],f:'你煎了两个蛋。\nTa看着你的动作——「还挺熟练。」\n「以前——也给人做过。」\n沉默了一秒——然后Ta把碗推过来。「那再煎一个。」'}]},
    {t:'教Ta做菜',minAff:30,x:'{{hs.e}} {{hs.n}}在厨房——对着菜谱皱眉。\n\n{{pk:「这个步骤——怎么翻面？」|锅铲举着——但不敢下手|正在准备明天的便当——但不太成功|说「我不是不会——只是在研究——」。}}',
      c:[{t:'「我来——你看着」接过锅铲',a:[{id:'hs',v:dv(7)}],f:'你演示了一遍。Ta认真地看——然后自己试了试。\n成品不太好看。但Ta端到你面前——「尝尝。」\n你吃了。然后点了点头。\nTa笑得——比任何考试满分都开心。'},
         {t:'在旁边指导——不动手',a:[{id:'hs',v:dv(5)}],f:'「火小一点——对——翻——」\nTa紧张得手在发抖。但翻过来了。\n「成功了——！！」\n然后他看了看你——\n「……比我一个人做——有意思多了。」'}]},
    {t:'各自看书',minAff:30,x:'晚间。\n\n你在看书。{{hs.e}} {{hs.n}}也在看书。\n\n{{pk:两人的书偶尔碰到一起|Ta的脚不小心碰到了你——但没缩回去|你翻页的时候——Ta正好也翻了一页|安静。只有翻书的声音}}。',
      c:[{t:'继续看——不打扰',a:[{id:'hs',v:dv(4)}],f:'你们各自看着书。\n偶尔抬头——目光撞上——然后各自转开。\n这种默契——已经不需要语言了。'},
         {t:'问他「看到哪里了？」',a:[{id:'hs',v:dv(5)}],f:'Ta翻过封面给你看。然后问「你那本好看吗？」\n你念了一段。Ta听得很认真。\n「下次——借我。」\n不是问句。是约定。'}]},
    // ─── 高好感(60+)：深度羁绊，温柔时刻 ───
    {t:'失眠',minAff:60,x:'半夜。\n\n你醒了——口渴。\n\n走出房间——发现{{hs.e}} {{hs.n}}也在客厅。\n\n{{pk:「你也睡不着？」|Ta在喝热牛奶|Ta没开灯——就坐在沙发上|两人对视——然后都懂了}}。',
      c:[{t:'坐下——「想聊聊吗？」',a:[{id:'hs',v:dv(10)}],f:'Ta沉默了一会儿。然后开口——说了些白天不会说的事。\n关于未来。关于害怕。关于——\n「有时候觉得——这个家太安静了。」\n然后看了看你。「你来了之后——好多了。」'},
         {t:'给Ta倒杯热牛奶——不说话陪着',a:[{id:'hs',v:dv(8)}],f:'你把杯子推过去。Ta双手捧着——热气在黑暗里升起来。\n\n「……谢谢。」\n声音很轻。\n但比任何大声的话都有重量。'}]},
    {t:'整理相册',minAff:60,x:'{{hs.e}} {{hs.n}}翻出一本旧相册。\n\n{{pk:「这是以前——」|「好丑——别看——」但没抢走|翻到某页时停了下来|里面有你们第一天来时的照片}}。\n\n时间在纸页间安静地躺着。',
      c:[{t:'认真地看着——每一页',a:[{id:'hs',v:dv(9)}],f:'Ta讲了每张照片的故事。\n有些好笑。有些——Ta说完就沉默了。\n然后翻到最后——空的。\n「以后——会有新的。」Ta说。「对吧。」\n你点了点头。'},
         {t:'指着一张照片——「这张给我一张？」',a:[{id:'hs',v:dv(7)}],f:'Ta愣了一下。然后小心地把照片抽出来——\n「给你。」\n然后顿了顿——\n「不过——以后还会有更好的。」\n说这话的时候——Ta没看你。但耳尖红了。'}]},
    {t:'弹琴/听歌',minAff:60,x:'{{hs.e}} {{hs.n}}{{pk:在弹吉他——很轻|打开了音响——一首老歌|哼着一段旋律——很好听|说「有首歌——想让你听。」}}。\n\n音符在房间里飘。\n\n{{pk:是Ta最喜欢的歌|是你没听过的旋律——但莫名熟悉|歌词里有句话——像是要说的|音乐停了——但氛围还在}}。',
      c:[{t:'安静地听完——「很好听」',a:[{id:'hs',v:dv(8)}],f:'歌放完了。\nTa看着你——\n「这是我很喜欢的一首。以前一个人听。」\n顿了顿。\n「现在——两个人。」\n然后笑了。很小。但很真。'},
         {t:'「下次也分享一首给你」',a:[{id:'hs',v:dv(7)}],f:'Ta的眼睛亮了一下。\n「好。」然后假装不在意——但你已经看到了。\n第二天早上——你的手机里多了一个歌单。\n名字是——「等你分享的那首。」'}]},
    {t:'收拾行李',minAff:60,x:'你在整理东西。\n\n{{hs.e}} {{hs.n}}敲了门——靠在门框上。\n\n{{pk:「需要帮忙吗？」|看到你摊开的东西——笑了一下|走过来——把一件折好的衣服放进行李箱|说「你还挺会收拾的——」}}。\n\n然后——Ta安静地看着你的东西。\n\n好像在数——还有多少天。',
      c:[{t:'「还有时间——不急。」',a:[{id:'hs',v:dv(10)}],f:'Ta没有说话。\n但帮你叠了下一件衣服。\n动作很慢——像是在拖延什么。\n然后说——「我知道。」\n不是给自己听的。是给你听的。'},
         {t:'「别帮我叠——坐这儿陪我就好」',a:[{id:'hs',v:dv(12)}],f:'Ta在床边坐下。\n看着你收拾。\n然后——很轻地——\n「你走了之后。」\n停了一下。\n「这个房间——我会留着。」\n他没有看你。但你知道——这是一句很重要的话。'}]},
    {t:'睡前',minAff:60,x:'夜深了。\n\n{{hs.e}} {{hs.n}}站在你房间门口。\n\n{{pk:「不早了——该睡了。」|「明天要早起。别熬夜。」|「晚安。」|靠在门框上——好像想说什么}}。',
      c:[{t:'「晚安。」认真地回',a:[{id:'hs',v:dv(5)}],f:'Ta关上了门。走廊的脚步声渐渐远了。你躺在床上——觉得今天过得不错。'},
         {t:'叫住Ta：「谢谢你让我住在这里」',a:[{id:'hs',v:dv(12)}],f:'Ta停住了。没有回头——但背影好像柔和了。\n「……别说这种话。」声音很轻。但你听到了。'}]},
  ],
};

// ─── 周末校外地点的随机事件类型（用 {{}} 作为占位符）───
const WEEKEND_TYPES=[
  {loc:'shopping',t:'周末·逛街偶遇',x:'周末的{{loc.n}}{{loc.e}}很热闹。\n\n你逛着逛着——迎面碰上了{{mc.e}} {{mc.n}}{{sc?和+sc.e+ +sc.n:}}。\n\n{{pk:「这么巧——你也来逛？」|「正好——帮我挑个东西。」|两只手提满了购物袋——看起来血拼了一上午。|「附近有家店很不错——要不要一起去？」}}',
    c:[{t:'「好巧！一起逛吧」',a:[{id:'mc',v:dv(6)}],f:'你们走在了一起。周末的街道——阳光正好。'},
       {t:'推荐一家附近的店',a:[{id:'mc',v:dv(4)}],f:'Ta眼睛亮了一下。「真的？带路——」'}],},
  {loc:'cafe',t:'周末·咖啡厅偶遇',x:'{{loc.n}}{{loc.e}}。\n\n你点了杯饮料坐下。\n\n旁边那桌——{{mc.e}} {{mc.n}}{{pk:在看书|在笔记本上写着什么|点了一杯和你一样的饮料|在发呆——看到你之后愣了一下}}。',
    c:[{t:'「可以坐一起吗？」',a:[{id:'mc',v:dv(7)}],f:'Ta合上书——点了点头。你们的桌子并到了一起。咖啡的香气混着午后的阳光。'},
       {t:'请Ta喝杯饮料',a:[{id:'mc',v:dv(5)}],f:'「这是你的——」Ta有些意外。捧着杯子的时候——手指很暖。'}],},
  {loc:'park',t:'周末·公园散步',x:'{{loc.n}}{{loc.e}}。\n\n阳光从树叶间落下来。\n\n你看到{{mc.e}} {{mc.n}}{{pk:在跑步|坐在长椅上看鸽子|在喂野猫|戴着耳机——一个人在听歌}}。',
    c:[{t:'走过去打招呼',a:[{id:'mc',v:dv(6)}],f:'Ta摘下耳机。你们沿着公园的小路走了一段——聊着些轻快的话题。'},
       {t:'坐在不远处——安静地陪着',a:[{id:'mc',v:dv(4)}],f:'Ta没有立刻发现你。但当你起身准备离开时——Ta叫住了你。「……刚看到你。」'}],},
  {loc:'cinema',t:'周末·电影院',x:'{{loc.n}}{{loc.e}}。\n\n{{mc.e}} {{mc.n}}站在排片表前——{{pk:犹豫要看哪部|在等朋友——但朋友迟到了|刚好看完一场出来|手里拿着爆米花——分量很大}}。',
    c:[{t:'「一起看吧——我也在犹豫」',a:[{id:'mc',v:dv(8)}],f:'你们选了一部电影。黑暗中——偶尔会一起笑。偶尔碰到手臂——没人挪开。'},
       {t:'帮Ta分析看哪部好',a:[{id:'mc',v:dv(4)}],f:'你给了建议。Ta点了点头——「听你的。」'}],},
  {loc:'bookstore',t:'周末·书店相遇',x:'{{loc.n}}{{loc.e}}。\n\n书架之间。\n\n你和{{mc.e}} {{mc.n}}同时伸手——\n\n拿的是同一本书。',
    c:[{t:'「你看这本？」笑着让给Ta',a:[{id:'mc',v:dv(8)}],f:'Ta接过书——然后说「看完告诉你感想。」后来——你真的收到了Ta的消息。'},
       {t:'「这本书很好看——推荐」',a:[{id:'mc',v:dv(5)}],f:'你说完——Ta认真地看了看简介。然后把书放进了购物篮。'}],},
  {loc:'arcade',t:'周末·游戏厅',x:'{{loc.n}}{{loc.e}}。\n\n电子音和灯光交织。\n\n{{mc.e}} {{mc.n}}{{pk:在抓娃娃——快成功了|在赛车游戏上刷新了记录|站在投篮机前——满脸认真|在推币机前——只剩最后一个币}}。',
    c:[{t:'「一起玩？」投币加入',a:[{id:'mc',v:dv(7)}],f:'你们PK了三局。各有胜负——但笑得比赢了还开心。'},
       {t:'帮Ta抓出了那个娃娃',a:[{id:'mc',v:dv(9)}],f:'爪子松了的那一刻——你迅速调整了角度。居然抓出来了。Ta惊叹「你怎么做到的——！？」'}],},
  {loc:'riverside',t:'周末·河边吹风',x:'{{loc.n}}{{loc.e}}。\n\n傍晚。风从水面上吹来。\n\n{{mc.e}} {{mc.n}}{{pk:靠着栏杆——看河水|在往水里扔石子|在遛狗——狗先跑过来蹭了你|一个人坐着——但看到你之后笑了}}。',
    c:[{t:'站在Ta旁边——不说话',a:[{id:'mc',v:dv(8)}],f:'你们沉默地看着河水。这种安静——比很多对话更有分量。'},
       {t:'「今天过得怎么样？」',a:[{id:'mc',v:dv(5)}],f:'Ta想了想。然后说——「不错。」然后看了你一眼。\n「……更好了。」'}],},
  {loc:'station',t:'周末·车站偶遇',x:'{{loc.n}}{{loc.e}}。\n\n{{mc.e}} {{mc.n}}{{pk:在等车|刚从车上下来——提着一堆东西|在看时刻表|坐错了方向——一脸懵}}。',
    c:[{t:'「你去哪里？一起走吧」',a:[{id:'mc',v:dv(6)}],f:'你们搭了同一班车。路上聊了很多——车窗外的风景一直在变。'},
       {t:'帮Ta拿东西/指路',a:[{id:'mc',v:dv(5)}],f:'「还好碰到你——」Ta松了口气。你帮Ta把东西搬上了车。'}],},
];

// ╔══════════════════════════════════════════════════════════════╗
// ║  主线+支线任务系统 (v5.0 - 仿Madoka Portable架构)            ║
