// ╔══════════════════════════════════════════════════════════════╗
// ║  因果值(Karma)系统 — 仿Madoka Portable跨轮回追踪            ║
// ╚══════════════════════════════════════════════════════════════╝

// ─── 因果值定义与存取 ───
// G.karma: 跨轮回累积（类似Madoka Portable因果值，每轮回继承）
// 存储：localStorage 'aotu4_karma'
function loadKarma(){try{const v=localStorage.getItem('aotu4_karma');return v?parseInt(v)||0:0;}catch(e){return 0;}}
function saveKarma(v){try{localStorage.setItem('aotu4_karma',String(v));console.log("💾 因果值已保存:",v);return true;}catch(e){return false;}}

// ─── 轮回结算：计算本轮回获得的因果值 ───
function calcKarmaEarned(){
  let karma=0;
  // 最高CP好感度奖励（除以4，避免暴涨）
  let maxCP=0;Object.entries(CP).forEach(([k])=>{const a=cpAvg(k);if(a>maxCP)maxCP=a;});
  karma+=Math.floor(maxCP/4); // 最高25
  // 支线完成奖励
  karma+=(G.completedSQ||[]).length*3; // 每个支线+3
  // SPR保持奖励
  if(G.attr.SPR>=5)karma+=5; // 精神稳定+5
  // 存活天数奖励
  karma+=Math.floor(G.day/10); // 每10天+1
  // 成就奖励
  karma+=(G.achievements||[]).length*1;
  // 好感度≥90角色奖励
  let highAff=0;Object.values(G.aff).forEach(v=>{if(v>=90)highAff++;});
  karma+=highAff*3;
  return karma;
}

// ─── 感情值波动机制（高好感→SPR更易消耗）───
// 仿Madoka Portable：感情值越高→灵魂宝石越容易黑化
function getSprVolatility(){
  let maxAff=0;Object.values(G.aff).forEach(v=>{if(v>maxAff)maxAff=v;});
  if(maxAff>=80)return 2;    // 深度羁绊：SPR消耗×2（因为有羁绊保护，净效果被抵消）
  if(maxAff>=60)return 1.5;  // 重要关系：SPR消耗×1.5
  if(maxAff>=40)return 1.2;  // 友谊：SPR消耗×1.2
  return 1;
}

// ─── 因果商店（轮回间消费）───
// 用于新游戏开始前消费因果值获得buff
const KARMA_SHOP=[
  {id:'ks_attr',n:'天赋异禀',e:'🌟',cost:50,d:'全属性+2（新轮回开始时生效）',eff:()=>{Object.keys(G.attr).forEach(k=>G.attr[k]=clamp(G.attr[k]+2,1,10));}},
  {id:'ks_aff5',n:'命运的引力',e:'💫',cost:30,d:'随机3个角色初始好感+10',eff:()=>{const pool=Object.keys(CH).sort(()=>Math.random()-0.5).slice(0,3);pool.forEach(k=>G.aff[k]=(G.aff[k]||0)+10);}},
  {id:'ks_spr',n:'钢之决意',e:'🧘',cost:40,d:'精神初始值+3，SPR不低于3',eff:()=>{G.attr.SPR=clamp(G.attr.SPR+3,1,10);G._ksSpr=true;}},
  {id:'ks_energy',n:'充沛活力',e:'🔋',cost:25,d:'每日体力+10',eff:()=>{G._ksEnergy=true;}},
  {id:'ks_home',n:'居場所',e:'🏠',cost:20,d:'可选择借宿角色（而非随机）',eff:()=>{G._ksHome=true;}},
  {id:'ks_bonus',n:'番外·回声',e:'🌌',cost:120,d:'解锁隐藏天赋"圆环之理"——前7天每天额外触发一次特殊事件',eff:()=>{G.talents.push('t_bonus');G.talentNames.push('圆环之理');G._tBonus=true;}},
];

// ─── 更新execChoice中的SPR消耗逻辑（加入感情值波动）───
// 在SPR计算中加入波动系数（在execChoice中调用）
function applySprVolatility(sprDelta){
  if(sprDelta<0){
    const vol=getSprVolatility();
    return Math.ceil(sprDelta*vol); // 高好感时损失更大
  }
  return sprDelta;
}

// ─── 游戏状态 ───
let G={
  name:'',gender:'neutral',day:1,maxDay:100,
  slot:'morning',energy:100,
  attr:{INT:0,CHR:0,STR:0,AFF:0,SPR:0},
  aff:{},flags:{},talents:[],talentNames:[],club:null,
  journal:[],memories:[],achievements:[],
  history:[],loop:1,phase:'title',
  homestay:null,dayType:'weekday',
  mainChapter:1,sideQuests:{},completedSQ:[],
  lowSprDays:0,sprWarned:false,dailyEvents:0,schoolStreak:0,karma:0,_ksSpr:false,_ksEnergy:false,_ksHome:false,_tBonus:false,_bonusToday:false,
  _tAngel:false,_tJournal:false,_tSeventh:false,_tWatch:false,
  _tStuco:false,_tSocial:false,_tEarly:false,_tNight:false,
  _tBento:false,_tRun:false,_tWeather:false,_tJoke:false,
  _tLucky:false,_tLib:false,_tRooftop:false,_tChill:false,
};
let curEv=null,toastQ=[];

function initG(){
  G.day=1;G.slot='morning';G.energy=100;
  G.attr={INT:rn(2,8),CHR:rn(2,8),STR:rn(2,8),AFF:rn(2,8),SPR:rn(2,8)}; // 随机属性！
  G.aff={};G.cpAff={};Object.keys(CH).forEach(k=>G.aff[k]=0);Object.keys(CP).forEach(k=>G.cpAff[k]=0);
  G.flags={};G.club=null;G.journal=[];G.memories=[];G.history=[];
  G.talents=[];G.talentNames=[];
  G.homestay=pk(HOMESTAY_POOL); // 随机借宿角色
  G.homeInfo=getHomeInfo(G.homestay); G.sideQuests={}; G.completedSQ=[]; G.lowSprDays=0; G.sprWarned=false; G.dailyEvents=0; G.schoolStreak=0;
  G.karma=loadKarma();applyKarmaPassive(); G._ksSpr=false; G._ksEnergy=false; G._ksHome=false; G._tBonus=false; G._bonusToday=false;
  ['_tAngel','_tJournal','_tSeventh','_tWatch','_tStuco','_tSocial','_tEarly','_tNight','_tBento','_tRun','_tWeather','_tJoke','_tLucky','_tLib','_tRooftop','_tChill'].forEach(k=>G[k]=false);
}
initG();

// ─── 工具 ───
function rn(a,b){return Math.floor(Math.random()*(b-a+1))+a;}
function pk(a){return a[Math.floor(Math.random()*a.length)];}
function dv(v){return Math.round(v+(Math.random()-0.5)*5);} // ±2.5范围偏差
function clamp(v,lo,hi){return Math.max(lo,Math.min(hi,v));}
function cpAvg(key){return G.cpAff?.[key]||0;}
function stageName(v){return v>=90?'💖心动':v>=70?'💗亲密':v>=50?'💛好友':v>=30?'💚朋友':v>=10?'🤝认识':'😶初识';}

// 检查因果商店物品是否已购买（从localStorage读取）
function hasKarmaItem(id){try{const b=JSON.parse(localStorage.getItem('aotu4_shop')||'[]');return b.includes(id);}catch(e){return false;}}

// ─── 日类型计算 ───
function calcDayType(day){
  if(typeof CAL!=='undefined'&&CAL[day]?.fest)return'festival';
  const mod=(day-1)%7;
  if(mod===5||mod===6)return'weekend';
  return'weekday';
}
function getDayName(day){
  const mod=(day-1)%7;
  return['周一','周二','周三','周四','周五','周六','周日'][mod];
}
function slotLabel(slot){
  const hs=CH[G.homestay];const home=G.homeInfo||getHomeInfo(G.homestay);
  const hn=home?`${home.isFamily?home.allEmoji+' '+home.displayName:hs.e+' '+hs.n+'家'}`:'';
  switch(slot){
    case'morning':return`🌅 早晨 · ${hn}`;
    case'class1':return'📖 上午课';
    case'noon':return'☀️ 午间';
    case'class2':return'📝 下午课';
    case'afternoon':return G.dayType==='weekend'?'☕ 午后时光':'🌆 放学后';
    case'evening':return`🌙 晚间 · ${hn}家`;
    default:return'';
  }
}

// ─── 存档 ───
function saveTo(slot){try{const d=JSON.parse(JSON.stringify(G));d._t=new Date().toISOString();localStorage.setItem('aotu4_'+slot,JSON.stringify(d));return true;}catch(e){return false;}}
function loadFrom(slot){const r=localStorage.getItem('aotu4_'+slot);if(!r)return false;try{G=JSON.parse(r);return true;}catch(e){return false;}}

