// ─── 随机属性分配器 ───
function randomizeAttrs(){
  const keys=['INT','CHR','STR','AFF','SPR'];
  const attrs={};keys.forEach(k=>attrs[k]=rn(1,5)); // 基础随机1-5
  let remain=15;
  // 随机投入剩余点数
  while(remain>0){
    const k=pk(keys);
    if(attrs[k]<10){attrs[k]++;remain--;}
  }
  return attrs;
}

// ─── 随机天赋选择器 ───
function randomizeTalents(){
  const pickCount=loadKarma()>=100?3:2; // 观测者以上：3选1

  const pool=[...TALENTS].sort(()=>Math.random()-0.5);
  // 根据权重概率抽取2个（高稀有度概率更低，但可能抽到）
  const selected=[];
  const weights=pk([...Array(5)].map((_,i)=>i)); // 随机决定抽卡偏向
  for(let i=0;i<pickCount;i++){
    const r=Math.random();
    let pick;
    if(r<0.05)pick=pool.find(t=>t.g>=5);     // 5%传说
    else if(r<0.20)pick=pool.find(t=>t.g===4); // 15%史诗
    else if(r<0.45)pick=pool.find(t=>t.g===3); // 25%稀有
    else if(r<0.75)pick=pool.find(t=>t.g===2); // 30%普通
    else pick=pool.find(t=>t.g<=1);            // 25%平凡
    if(!pick||selected.find(s=>s.id===pick.id))pick=pool.find(t=>!selected.find(s=>s.id===t.id));
    if(pick)selected.push(pick);
  }
  return selected.slice(0,pickCount);
}

