window._nav=function(p){render(p);};
window._save=function(){saveTo(0);render('play',{msg:'💾 已快速存档。',changes:[]});};
window._toggleAI=function(){
  AI_ENABLED_global=!AI_ENABLED_global;
  localStorage.setItem('aotu_ai_enabled',AI_ENABLED_global?'true':'false');
  render('play',{msg:AI_ENABLED_global?'🤖 AI对话已开启 —— 角色将根据性格实时生成个性化文本':'📋 AI对话已关闭 —— 使用静态对话模板',changes:[]});
};

// ⚡ 批量预生成：每个角色1次API调用，生成全部事件类型（18次总计~1分钟）
window._prewarm=async function(){
  const chars=Object.keys(CH).filter(k=>CH[k]&&CH[k].c!=='教师');
  let done=0,errors=0;
  render('play',{msg:`⚡ 批量生成中... ${done}/${chars.length} 角色`,changes:[]});

  for(const charId of chars){
    try{
      const resp=await fetch('/api/batch',{
        method:'POST',headers:{'Content-Type':'application/json'},
        body:JSON.stringify({charId}),
      });
      if(resp.ok){
        const data=await resp.json();
        if(data.results){
          for(const [key,val] of Object.entries(data.results)){
            if(val&&val.narration){AI_CACHE[key]=val;}
          }
          saveAiCache();
        }
      }else{errors++;}
    }catch(e){errors++;}
    done++;
    if(done%3===0||done===chars.length){
      render('play',{msg:`⚡ 进度: ${done}/${chars.length} 角色 (${errors}失败)`,changes:[]});
    }
    // 速率限制
    await new Promise(r=>setTimeout(r,1500));
  }

  saveAiCache();
  const cacheCount=Object.keys(AI_CACHE).length;
  render('play',{msg:`✅ 批量生成完成！\n📊 ${done} 角色 · 缓存总数 ${cacheCount} 条\n🔒 之后这些对话永久缓存，不再消耗API。`,changes:[]});
};

function rPlay(app,feedback){
  if(G.day>G.maxDay){render('end');return;}

  // 日历事件检查（在任何时段都优先）
  const cal=CAL[G.day];
  if(cal&&!G.flags['cal_'+G.day]&&!feedback){
    G.flags['cal_'+G.day]=true;G.dayType='festival';
    if(cal.fest){curEv={type:'calendar',narration:`🎪 Day ${G.day} · ${cal.n}\n\n`+cal.x,choices:[
      {t:'全身心投入每一个活动',a:Object.keys(CH).slice(0,14).map(k=>({id:k,v:dv(5)})),f:cal.n+'——你在人群中，笑着。这会是回忆里闪闪发光的一天。'},
      {t:'在人群之外安静地享受',a:[],f:'你在角落看着所有人。这种距离——也很舒服。'},
    ]};render('event');return;}
    if(cal.cp&&CPS[cal.cp]?.[cal.st]){
      const sd=CPS[cal.cp][cal.st];
      curEv={type:'cp',cp:cal.cp,stage:cal.st,narration:`💫 ${CP[cal.cp]?.n||''} · Day ${G.day}\n\n`+sd.x,choices:sd.c};
      render('event');return;
    }
    if(cal.club){
      curEv={type:'calendar',narration:`📅 Day ${G.day} · ${cal.n}\n\n`+cal.x,choices:[
        {t:'加入文艺社（银爵🐱）',a:[{id:'yinjue',v:8}],f:'银爵点了点头。「欢迎。猫可以摸——但不要吵到它。」',club:'文艺社'},
        {t:'加入美术社（凯莉👑）',a:[{id:'kaili',v:8}],f:'凯莉打量了你一下。「嗯——可以。下午茶时间是四点。」',club:'美术社'},
        {t:'加入体育社（佩利🐺）',a:[{id:'peili',v:8},{id:'jin',v:3}],f:'佩利拍了一下你的背（很重）。「好！！以后一起跑步！！」',club:'体育社'},
        {t:'不加入任何社团，保持自由',a:[],f:'你没有加入社团。归属感减少了，但自由时间增加了。',club:null},
      ]};render('event');return;
    }
    if(cal.aa||cal.attr){const chs=[{t:'认真地度过这一天',a:cal.aa?Object.keys(CH).filter(k=>CH[k]).map(k=>({id:k,v:dv(cal.aa)})):[],f:`${cal.n}——这一天结束了。`}];
      if(cal.attr){Object.entries(cal.attr).forEach(([k,v])=>{G.attr[k]=clamp(G.attr[k]+v,1,10);});}
      curEv={type:'calendar',narration:`📅 Day ${G.day} · ${cal.n}\n\n`+cal.x,choices:chs};render('event');return;
    }
  }

  if(feedback){renderFB(app,feedback);return;}

  // ─── 体力不足请假检查（每次≤50必定触发）───
  if(!feedback&&G.energy<=50&&(G.slot==='afternoon'||G.slot==='evening')&&!G.flags['sick_leave_'+G.day]){
    G.flags['sick_leave_'+G.day]=true;
    const hs=CH[G.homestay];
    const home=G.homeInfo||getHomeInfo(G.homestay);
    let sickCarer=hs?hs.e+' '+hs.n:'';
    if(home&&home.isFamily&&home.otherMembers.length>0&&Math.random()<0.5){
      const famMember=pk(home.otherMembers);
      sickCarer=famMember.e+' '+famMember.n;
    }
    curEv={type:'sick_leave',narration:`🏥 体力不支\n\n你感到一阵眩晕。\n\n这几天太拼了——身体在抗议。\n\n${sickCarer}注意到你的脸色：「你该休息了。」\n\n请假条就在桌上。\n\n两天——好好睡一觉。`,
      choices:[
        {t:'请假休息两天（跳过Day '+(G.day+1)+'~'+(G.day+2)+'，能量回满，SPR+2）',a:[],f:'你把请假条放在桌上。\n\n钻进被窝——意识很快模糊了。\n\n醒来时——窗外已经是第三天早晨。\n\n身体轻了很多。',skip:2,heal:true},
        {t:'硬撑着继续（体力-15 · 精神-1~2）',a:[],f:'你喝了一杯咖啡。\n\n「没事。」你对关心的人说。\n\n但头痛欲裂——身体和心灵都在抗议。',skip:0,heal:false},
      ]};
    render('event');return;
  }

  // ─── SPR归零检查：连续2天低精神 → 心魔幻境 ───
  if(G.lowSprDays>=2&&G.slot==='morning'&&!G.flags['heart_demon_today']){
    G.flags['heart_demon_today']=true;
    curEv={type:'heart_demon',narration:`💀 心魔幻境\n\n连续${G.lowSprDays}天的精神低潮——\n\n你的意识开始模糊。教室的墙壁在融化。\n\n同学的面孔扭曲成幻影。\n\n有人——不，有什么——在黑暗中注视着你。\n\n那些你最在意的人——变成了你最深的梦魇。\n\n只有战胜他们——才能回来。`,
      choices:[{t:'⚔️ 踏入心魔幻境',a:[],f:''}]};
    render('event');return;
  }

  // ─── 好感度满特殊剧情检查（双结局：挚友/恋人）───
  if(!feedback&&G.slot==='morning'){
    for(const[id,data]of Object.entries(AFF90_EVENTS)){
      if(G.flags['aff90_pending_'+id]){
        G.flags['aff90_pending_'+id]=false;
        G.memories.push('cg_'+id);
        curEv={type:'aff90',ch:id,narration:`💖 ${data.n}\n\n${data.x}`,choices:[
          {t:data.c_friend.t,f:data.c_friend.f,choice:'friend'},
          {t:data.c_love.t,f:data.c_love.f,choice:'love',lockCPs:data.c_love.lockCPs||[]},
        ]};
        render('event');return;
      }
    }
  }

  // ─── 主线章节检查 ───
  if(!feedback&&G.slot==='morning'){
    const mc=checkMainChapter();
    if(mc&&!G.flags['main_done_'+G.mainChapter]){
      G.flags['main_done_'+G.mainChapter]=true;
      let narration=`📖 主线 · 第${G.mainChapter}章：${mc.t}\n\n${mc.d}`;
      // Day 100：根据好感度动态追加角色个性化告别
      if(G.mainChapter===10){
        const farewells=[];
        if((G.aff.paluosi||0)>=30) farewells.push('帕洛斯🖊️递给你一本新书的试读——扉页写着：「下一本的主角——我改成你了。」');
        if(farewells.length>0) narration+='\n\n'+farewells.join('\n');
      }
      curEv={type:'mainstory',ch:mc.t,narration,choices:[
        {t:'继续前进',a:Object.keys(CH).filter(k=>CH[k]).slice(0,8).map(k=>({id:k,v:dv(4)})),f:`第${G.mainChapter}章——${mc.t}。你的人生——从这里开始改变。`}
      ]};
      render('event');return;
    }
  }
  // ─── 支线检查（放学后时段）───
  const sqChance=0.3+getKarmaEventBonus(); if(!feedback&&G.slot==='afternoon'&&Math.random()<sqChance){
    const sqResult=checkSideQuest();
    if(sqResult){
      triggerSideQuest(sqResult.sq,sqResult.step);
      return;
    }
  }

  // 根据时段和日类型分发
  // 事件缓存：从MENU返回时复用已生成的事件，避免刷新
  const slotCacheKey=G.slot+'_'+G.day;
  if(!feedback&&G._eventCache&&G._eventCache[slotCacheKey]&&G._eventCache[slotCacheKey].length>0){
    const cached=G._eventCache[slotCacheKey];
    if(G.slot==='class1'||G.slot==='class2')renderEventSelect(app,cached,'📖 '+(G.slot==='class1'?'上午课':'下午课'),null);
    else if(G.slot==='noon')renderEventSelect(app,cached,'☀️ 午间 —— 大家都在做什么？','<div style="text-align:center;margin-top:10px"><button class="btn btn-s" onclick="window._adv()">跳过 ▸</button></div>');
    else if(G.slot==='afternoon')renderEventSelect(app,cached,'🌆 放学了 —— 今天发生着这些事……','<div style="display:flex;gap:6px;margin-top:10px;justify-content:center"><button class="btn btn-s" onclick="window._rest()" style="border-color:var(--green);color:var(--green)">🧘 回家休息（恢复SPR+体力）</button></div>');
    else if(G.dayType==='weekend'||G.dayType==='festival'){
      const label=G.slot==='noon'?'上午':'午后';
      renderEventSelect(app,cached,(label==='上午'?'🏙️ 周末上午 —— 去哪里逛逛？':'☕ 周末午后 —— 有什么在等着呢？'),'<div style="text-align:center;margin-top:10px"><button class="btn btn-s" onclick="window._adv()">随便逛逛 ▸</button></div>');
    }
    return;
  }
  const slot=G.slot;const dt=G.dayType;
  if(dt==='weekend'||dt==='festival'){
    if(slot==='morning'){renderMorning(app);return;}
    if(slot==='noon'){renderWeekendExplore(app,'上午');return;}
    if(slot==='afternoon'){renderWeekendExplore(app,'午后');return;}
    if(slot==='evening'){renderEvening(app);return;}
    // 周末跳过class1/class2，自动推进
    if(slot==='class1'||slot==='class2'){advanceSlot();render('play');return;}
  } else {
    // 工作日
    if(slot==='morning'){renderMorning(app);return;}
    if(slot==='class1'||slot==='class2'){renderClass(app);return;}
    if(slot==='noon'){renderNoon(app);return;}
    if(slot==='afternoon'){renderAfternoon(app);return;}
    if(slot==='evening'){renderEvening(app);return;}
  }
  // 兜底
  advanceSlot();render('play');
}

function advanceSlot(){
  G._eventCache={}; // 清除事件缓存，时段变化后重新生成
  const dt=G.dayType;
  switch(G.slot){
    case'morning':
      if(dt==='weekend'||dt==='festival')G.slot='noon';
      else {G.slot='class1';G.energy=Math.max(0,G.energy-rn(3,5));} // 早晨出门消耗
      break;
    case'class1':G.slot='noon';
      // 上完上午课——精神微耗
      if(dt==='weekday')G.attr.SPR=clamp(G.attr.SPR-rn(0,1),0,10);
      break;
    case'noon':
      if(dt==='weekend'||dt==='festival')G.slot='afternoon';
      else G.slot='class2';
      break;
    case'class2':G.slot='afternoon';
      // 上完下午课——精神微耗
      if(dt==='weekday')G.attr.SPR=clamp(G.attr.SPR-rn(0,1),0,10);
      break;
    case'afternoon':G.slot='evening';break;
    case'evening':
      // 频繁社交疲劳检查（今日参与事件≥2 → 精神消耗）
      if(G.dailyEvents>=4){
        G.attr.SPR=clamp(G.attr.SPR-2,0,10); // 社交过度
      }else if(G.dailyEvents>=2){
        G.attr.SPR=clamp(G.attr.SPR-1,0,10); // 社交疲劳
      }
      // 低体力入睡前额外精神消耗（体力<25 → 焦虑失眠）
      if(G.energy<=25){
        G.attr.SPR=clamp(G.attr.SPR-rn(1,2),0,10);
      }
      G.slot='morning';G.day++;G.dailyEvents=0; // 重置每日事件计数
      // 连续上学天数追踪
      if(G.dayType==='weekend'||G.dayType==='festival'){G.schoolStreak=0;}
      else{G.schoolStreak=(G.schoolStreak||0)+1;}
      // 精神低迷拖累体力恢复（SPR≤3 → 回血减半）
      const sprLowPenalty=G.attr.SPR<=3?0.5:1;
      G.energy=Math.min(100,Math.floor((60+G.attr.STR*3)*sprLowPenalty));
      G.dayType=calcDayType(G.day);
      // 每日SPR消耗：周末/假日恢复，工作日微降
      if(G.dayType==='weekend'||G.dayType==='festival'){
        G.attr.SPR=clamp(G.attr.SPR+1,0,10); // 周末自然恢复+1
      } else {
        // 基础消耗
        let dailySprCost=1;
        // 考试日精神消耗翻倍
        const cal=CAL[G.day-1];
        if(cal&&(cal.n.includes('考试')||cal.n.includes('小测')||cal.n.includes('测验')))dailySprCost=2;
        // 周一忧郁（周末后返校）
        if(getDayName(G.day)==='周一')dailySprCost+=1;
        // 临近离别焦虑（Day 80+，倒计时压力）
        if(G.day>=80)dailySprCost+=1;
        // 连续上学疲劳（≥3天无休）
        if(G.schoolStreak>=5)dailySprCost+=2;
        else if(G.schoolStreak>=3)dailySprCost+=1;
        G.attr.SPR=clamp(G.attr.SPR-dailySprCost-getKarmaSprPenalty(),0,10);
      }
      // 高体力入睡 → 额外SPR恢复；低体力 → 额外消耗
      if(G.energy>=80)G.attr.SPR=clamp(G.attr.SPR+1,0,10);
      else if(G.energy>=60)G.attr.SPR=clamp(G.attr.SPR+rn(0,1),0,10);
      else if(G.energy<=30)G.attr.SPR=clamp(G.attr.SPR-1,0,10); // 体力不足入睡困难
      break;
  }
  // 体力归零惩罚：精神受损
  if(G.energy<=0){
    G.energy=0;
    G.attr.SPR=clamp(G.attr.SPR-1,0,10);
  }
  // 🛡️ 钢之决意：SPR不低于3
  if(G._ksSpr&&G.attr.SPR<3)G.attr.SPR=3;
  // 🔋 充沛活力：每日体力+10
  if(G._ksEnergy)G.energy=Math.min(100,G.energy+10);
  // 🌌 番外·回声：前7天标记额外事件
  if(G._tBonus&&G.day<=7)G._bonusToday=true;
}
window._adv=function(){
  curEv=null;
  advanceSlot();
  if(G.day>G.maxDay){render('end');return;}
  render('play');
};

// ─── 早晨渲染（借宿剧情）───
// 🌌 番外·回声 — 前7天每日特殊事件（因果商店120消费解锁）
function genBonusEvent(){
  const day=G.day;
  const evs=[
    {x:`🌌 番外·回声 · Day ${day}\n\n你做了一个梦。\n\n梦里——这个世界你已经来过很多次了。\n每一张脸都熟悉。每一个转角——都发生过什么。\n\n你在梦中伸出手——\n抓住了什么。\n\n醒来时——手心是温的。`,c:[{t:'「这不是第一次了——对吗？」',a:[],f:'你没有对任何人说。但今天——你看每个人的眼神——都多了一层东西。'},{t:'把梦记在日记里',a:[],f:'梦会消散。但文字不会。\n你写下了梦里记得的一切——\n然后发现——这些不是梦。\n是记忆。'}]},
    {x:`🌌 番外·回声 · Day ${day}\n\n课间。\n\n你路过走廊。\n\n有人在讨论——「转校生好像来过我们学校一样」——\n「你怎么知道——」「上课回答的问题——」\n「不是课本上的——像是经历过——」\n\n你停下来。她们看到你——不好意思地散了。\n但你知道——她们说的是真的。`,c:[{t:'微笑——然后继续走',a:[],f:'她们不知道的是——你的确来过。\n无数次。\n每一次——你都会找到他们。'},{t:'回头——记住那两个人的脸',a:[],f:'观察者。\n她们的名字不重要。\n但对这个世界——有人开始注意到了。\n这是因果的痕迹。'}]},
    {x:`🌌 番外·回声 · Day ${day}\n\n放学路上。\n\n你看到了一个熟悉的背影。\n\n是某个人——但不是今天认识的那个人。\n是上周目的。\n\n你愣在原地。\n那人走远了。\n\n你慢慢意识到——\n不是错觉。\n\n因果值越高——\n两个世界的边界就越薄。`,c:[{t:'追上去——但叫不出名字',a:[],f:'你追了几步。然后停下来。\n因为他已经——不记得你了。\n但下次。\n下次你一定——会从一开始就遇到他。'},{t:'站住——让记忆沉淀',a:[],f:'有些相遇——不在这个周目。\n但因果记得。\n你记得。\n这就够了。'}]},
    {x:`🌌 番外·回声 · Day ${day}\n\n你坐在借宿的房间里。\n\n窗外是同样的星空。\n\n但你突然想到——\n在另一个轮回里——\n你是不是也在这个房间——\n在同一个时间——\n想着同一件事？\n\n每一次的细微选择——\n汇成了不同的河流。\n但你总是在这里。\n总是和他们在一起。`,c:[{t:'看向窗外的星空',a:[],f:'命运是河流。\n你是船上的人——也是撑船的人。\n每一条支流——你都走过。'},{t:'写下此刻的想法',a:[],f:'文字模糊了。\n不是因为墨水——\n是你自己在不同周目的记忆交叠。\n你看到了自己写过的——\n也看到了自己将要写的。'}]},
    {x:`🌌 番外·回声 · Day ${day}\n\n有人在轻轻呼唤你的名字。\n\n你回头——没有人。\n\n但你听到了。\n\n那是上次——上上次——\n那些曾经把你看得很重要的人——\n的残响。\n\n声音很轻。\n像是在说——\n「又见到你了。」`,c:[{t:'「嗯。我回来了。」',a:[],f:'你的声音也很轻。\n轻到只有因果能听见。\n但——足够了。\n这是你第N次回到这里。\n每一次——都是新的。'},{t:'闭上眼睛——感受羁绊的重量',a:[],f:'不是幻觉。\n是因果。\n是无数次选择织成的网。\n你站在网的中心——\n被每一根丝线温柔地拉着。'}]},
    {x:`🌌 番外·回声 · Day ${day}\n\n同一个场景又出现了。\n\n这一次——\n你提前知道谁会在转角出现。\n\n你等在那里。\n他出现了。\n\n「——你在等我？」\n\n你点了点头。\n\n「你怎么知道我会从这里过——」\n\n你笑了笑——没有解释。\n\n有些事——不用解释。`,c:[{t:'「我也不知道。就是想等等看。」',a:[],f:'你没办法告诉他——\n你已经见过这个场景太多次了。\n但每次——\n他的表情——都不一样。\n这让你觉得——一切都值得。'},{t:'「只是一个感觉罢了」',a:[],f:'他歪了歪头——\n似乎在消化这句话。\n然后笑了。\n「你这个人——挺有意思的。」\n你心想：你也是。每次都一样有意思。'}]},
    {x:`🌌 番外·回声 · Day ${day}\n\n第七天。\n\n你站在校门口。\n\n回头看。\n\n100天很短。\n但你知道吗——\n这不是第一次。也不是最后一次。\n\n你想起每一个曾经告别的瞬间——\n每一次——你都选择了回来。\n\n因为这里——\n有你在乎的人。\n\n第7天的夕阳很暖。\n你走进了校门——\n一如往常。\n\n圆环在转动。\n而你——\n选择了继续。`,c:[{t:'走进校门——新的一天',a:[],f:'圆环永无止境。\n但你不是在重复。\n你是在——一点点接近某种东西。\n某种比轮回更重要的东西。'},{t:'回头看了一眼——然后笑了',a:[],f:'你看见了。\n所有周目的你——\n都在同一刻回了头。\n然后都笑了。\n\n因为答案是一样的——\n你们都知道。'}]},
  ];
  const ev=evs[Math.min(day-1,evs.length-1)];
  if(!ev)return null;
  return {type:'bonus',narration:ev.x,choices:ev.c,chars:[]};
}

function renderMorning(app){
  // 🌌 番外·回声：前7天额外特殊事件
  if(G._bonusToday){
    G._bonusToday=false;
    const bonusEv=genBonusEvent();
    if(bonusEv){curEv=bonusEv;render('event');return;}
  }
  const hs=CH[G.homestay];if(!hs){advanceSlot();render('play');return;}
  const home=G.homeInfo||getHomeInfo(G.homestay);
  // 周末早晨：提供"睡懒觉"选项
  if(G.dayType==='weekend'||G.dayType==='festival'){
    const sprGain=rn(1,2);
    const homeLabel=home.isFamily?`${home.allEmoji} ${home.displayName}`:`${hs.e} ${hs.n}家`;
    app.innerHTML=buildShell(`<div class="panel fadein" style="text-align:center"><h2>🌅 周末早晨 · ${homeLabel}</h2>
      <p style="color:var(--dim);line-height:2">阳光从窗帘缝隙漏进来。<br>今天不用早起。</p>
      <div style="display:flex;gap:8px;justify-content:center;flex-wrap:wrap">
        <button class="btn btn-p" onclick="window._sleepIn()" style="border-color:var(--green)">🛏️ 睡个懒觉（SPR+${sprGain}，体力恢复）</button>
        <button class="btn btn-s" onclick="window._adv()">起床出门 ▸</button>
      </div></div>`);
    return;
  }
  // 40%触发借宿事件
  if(Math.random()<0.4||G._tEarly){
    const ev=genHomeEvent('morning');
    if(ev){curEv=ev;render('event');return;}
  }
  // 否则简短早晨（融入角色个性风味，家庭成员偶尔出镜）
  const flav=getFlavor(G.homestay);
  const homeLabel=home.isFamily?`${home.allEmoji} ${home.displayName}`:`${hs.e} ${hs.n}家`;
  const msgs=[`🏠 ${homeLabel}。`,`清晨的阳光照进来。`];
  if(flav&&Math.random()<0.6)msgs.push(flav.morning);
  else if(home.isFamily&&home.otherMembers.length>0&&Math.random()<0.4){
    const other=pk(home.otherMembers);
    msgs.push(`${other.e} ${other.n}已经在餐桌旁了——「早。」`);
  }
  else if(Math.random()<0.3)msgs.push(`${hs.n}在厨房——「早餐快好了——」`);
  else msgs.push(`新的一天。${getDayName(G.day)}。`);
  app.innerHTML=buildShell(`<div class="panel fadein" style="text-align:center"><h2>🌅 早晨 · ${homeLabel}</h2><p style="color:var(--dim);line-height:2">${msgs.join('<br>')}</p><button class="btn btn-p" onclick="window._adv()">出门上学 ▸</button></div>`);
}

// ─── 周末睡懒觉 ───
window._sleepIn=function(){
  const sprGain=rn(2,3);const energyGain=rn(20,30);
  G.attr.SPR=clamp(G.attr.SPR+sprGain,0,10);
  G.energy=Math.min(100,G.energy+energyGain);
  const hs=CH[G.homestay];
  const home=G.homeInfo||getHomeInfo(G.homestay);
  let wakeMsg=hs?hs.e+' '+hs.n+'已经起来了——「周末嘛，多睡会儿没关系。」':'';
  if(home&&home.isFamily&&home.otherMembers.length>0&&Math.random()<0.5){
    const other=pk(home.otherMembers);
    wakeMsg=other.e+' '+other.n+'路过你房门口——「嘘，让他/她多睡会儿。」';
  }
  const msg=`🛏️ 你睡到了自然醒。\n\n${wakeMsg}\n\n充足的睡眠是最好的恢复。\n\n感觉整个人都轻了。`;
  G.journal.push({day:G.day,t:msg});
  curEv=null;
  advanceSlot(); // 跳到午间
  if(G.day>G.maxDay){render('end');return;}
  render('play',{msg,changes:[],sprDelta:sprGain});
};

// ─── 课堂渲染 ───
function renderClass(app){
  const tn=G.slot==='class1'?'📖 上午课':'📝 下午课';
  if(Math.random()<0.7){ // 70%概率有课堂事件
    // 课堂事件不需要地点——在高一B班教室
    const locs=['classroom','classroom']; // 虚拟地点池，用于占位
    const events=genEventPreviews(locs,3,genClassEvent,{isClass:true});
    if(events.length>0){
      // 课堂事件不需要地点信息，简化显示
      events.forEach(ev=>{ev.locName='高一B班教室';ev.locEmoji='📖';});
      renderEventSelect(app,events,`${tn} —— 教室里……`,
        '<div style="text-align:center;margin-top:10px"><button class="btn btn-s" onclick="window._adv()">认真听课 ▸</button></div>');
      return;
    }
  }
  // 无事件时简短描述
  const msgs=[`${tn}。课在进行中。`];
  const rc=CH[pk(Object.keys(CH).filter(k=>CH[k]&&CH[k].c==='高一B'))];
  if(rc)msgs.push(`${rc.e} ${rc.n}${pk(['在认真做笔记','从窗外收回目光——继续听课','悄悄伸了个懒腰','在转笔——笔掉了','翻了一页书'])}。`);
  app.innerHTML=buildShell(`<div class="panel fadein" style="text-align:center"><h2>${tn}</h2><p style="color:var(--dim);line-height:2">${msgs.join('<br>')}</p><button class="btn btn-p" onclick="window._adv()">继续 ▸</button></div>`);
}

// ─── 午间渲染 ───
