  app.innerHTML=buildShell(`<div class="panel fadein" style="text-align:center"><h2>☀️ 午间</h2><p style="color:var(--dim);line-height:2">${msgs.join('<br>')}</p><button class="btn btn-p" onclick="window._adv()">继续 ▸</button></div>`);
