// ─── 周末自由探索渲染 ───
function renderWeekendExplore(app,label){
  const locPool=Object.keys(LC_OUT);
  const events=genEventPreviews(locPool,4,genWeekendEvent,{cpChance:G._tSeventh?0.35:0.20});
  const title=label==='上午'?'🏙️ 周末上午 —— 去哪里逛逛？':'☕ 周末午后 —— 有什么在等着呢？';
  if(events.length>0){
    renderEventSelect(app,events,title,
      `<div style="text-align:center;margin-top:10px"><button class="btn btn-s" onclick="window._adv()">随便逛逛 ▸</button></div>`);
    return;
  }
  // 无事件时保留选择
  app.innerHTML=buildShell(`<div class="panel fadein"><h2>${label==='上午'?'🏙️ 上午自由时间':'☕ 午后时光'}</h2><p style="color:var(--dim);font-size:0.8em">周末——校园外有什么在等着呢？</p><div style="display:grid;grid-template-columns:repeat(2,1fr);gap:6px">
    ${Object.entries(LC_OUT).map(([id,loc])=>`<button class="btn btn-loc" onclick="window._goOut('${id}')"><span class="locemoji">${loc.e}</span><div class="locinfo"><div class="locname">${loc.n}</div><div class="lochars">${loc.ch.filter(c=>CH[c]&&G.aff[c]>=10).slice(0,4).map(c=>CH[c].e).join('')||'🔍 探索'}</div></div></button>`).join('')}
  </div><div style="text-align:center;margin-top:8px"><button class="btn btn-s" onclick="window._adv()">随便逛逛 ▸</button></div></div>`);
}
window._goOut=function(locId){
  G.energy=Math.max(0,G.energy-Math.max(3,11-G.attr.STR));curEv=null; // 体力高消耗少
  // CP事件触发
  const cpChance=G._tSeventh?0.35:0.20;
  if(Math.random()<cpChance){
    const avail=Object.entries(CPS).filter(([key,data])=>{
      let stage=1;if(G.flags["cp_"+key+"_s1"])stage=2;if(G.flags["cp_"+key+"_s2"])stage=3;if(G.flags["cp_"+key+"_s3"])stage=4;if(G.flags["cp_"+key+"_s4"])stage=5;
      if(!data[stage])return false;
      const avg=cpAvg(key);
      if(stage===1&&avg<10)return false;if(stage===2&&avg<25)return false;if(stage===3&&avg<45)return false;if(stage===4&&avg<60)return false;if(stage===5&&avg<75)return false;
      return !G.flags['cp_'+key+'_s'+stage+'_done'];
    });
    if(avail.length>0){
      // 按CP好感度加权随机选择
      const weights=avail.map(([key])=>cpAvg(key)+1);
      const totalW=weights.reduce((a,b)=>a+b,0);
      let r=Math.random()*totalW,s=0;
      const pick2=avail[weights.findIndex(w=>(s+=w)>r)];
      const[key,data]=pick2;let stage=1;
      if(G.flags['cp_'+key+'_s1'])stage=2;if(G.flags['cp_'+key+'_s2'])stage=3;
      if(data[stage]){
        G.flags['cp_'+key+'_s'+stage+'_done']=true;
        curEv={type:'cp',cp:key,stage,narration:`💫 ${CP[key]?.n||''} · Day ${G.day}\n\n`+data[stage].x,choices:data[stage].c};
        render('event');return;
      }
    }
  }
  const ev=genWeekendEvent(locId);
  if(ev){curEv=ev;render('event');}
  else render('play',{msg:'这里今天很安静。也许换个时间会有不同的偶遇。',changes:[]});
};

